// Extract body data to top level for easier access
const body = $input.first().json.body;

// Format booking time from Monday.com's display text (already in UK time)
let formattedBooking = 'TBC';
if (body.columnValues?.bookingTime?.text) {
  const raw = body.columnValues.bookingTime.text;

  const match = raw.match(/(\d{4})-(\d{2})-(\d{2})\s+(\d{2}):(\d{2})/);
  if (match) {
    const [, year, month, day, hours, minutes] = match.map(Number);

    const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
    const months = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

    const date = new Date(Date.UTC(year, month - 1, day));
    const dayName = days[date.getUTCDay()];
    const monthName = months[month - 1];

    const ordinal = (d) => {
      if (d > 3 && d < 21) return 'th';
      switch (d % 10) {
        case 1: return 'st';
        case 2: return 'nd';
        case 3: return 'rd';
        default: return 'th';
      }
    };

    let hrs = hours;
    const mins = minutes.toString().padStart(2, '0');
    const ampm = hrs >= 12 ? 'PM' : 'AM';
    hrs = hrs % 12 || 12;
    const timeStr = `${hrs.toString().padStart(2, '0')}:${mins}${ampm}`;

    formattedBooking = `${dayName} ${day}${ordinal(day)} ${monthName} at ${timeStr}`;
  } else {
    formattedBooking = raw;
  }
}

return {
  json: {
    eventType: body.eventType,
    webhookType: body.webhookType,
    itemId: body.itemId,
    boardId: body.boardId,
    itemName: body.itemName,
    status: body.status,
    previousStatus: body.previousStatus,
    service: body.service,
    clientType: body.clientType,
    passcode: body.passcode,
    email: body.columnValues?.email || '',
    phone: body.columnValues?.phone || '',
    company: body.columnValues?.company || '',
    imeiSn: body.columnValues?.imeiSn || '',
    formattedBooking: formattedBooking,
    gophrLink: body.columnValues?.gophrLink || '',
    gophrTimeWindow: body.columnValues?.gophrTimeWindow || '',
    outboundTracking: body.columnValues?.outboundTracking || '',
    intercomId: body.columnValues?.intercomId || '',
    ticketUrl: body.columnValues?.ticketLink?.url || ''
  }
};

