// Get original data from Extract Data node
const originalData = $('Extract Data').first().json;

// Get contact info from Intercom API response
const contact = $input.first().json;

// Extract first name from Intercom contact
// Falls back to Monday item name if Intercom name unavailable
let contactFirstName = originalData.itemName; // default fallback

if (contact?.name) {
  // Intercom contact has a name - take the first name only
  contactFirstName = contact.name.split(' ')[0];
} else if (contact?.first_name) {
  // Some Intercom versions use first_name directly
  contactFirstName = contact.first_name;
}

return {
  json: {
    ...originalData,
    contactFirstName: contactFirstName
  }
};

